// frontend/src/components/jobs/JobDetail.jsx
import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../../services/api'; 

const JobDetail = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const [job, setJob] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        // Memanggil endpoint: /api/jobs/:id
        api.get(`/jobs/${id}`) 
            .then(res => {
                // Backend mengirim { data: {...} }
                setJob(res.data.data); 
                setLoading(false);
            })
            .catch(err => {
                console.error("Gagal memuat detail:", err);
                setLoading(false);
            });
    }, [id]);

    if (loading) return <div>Memuat data...</div>;
    if (!job) return <div>Lowongan tidak ditemukan.</div>;

    return (
        <div style={{ maxWidth: '800px', margin: '40px auto', padding: '20px', color: '#fef3c7' }}>
            <button onClick={() => navigate(-1)}>Kembali</button>
            <h2>{job.title}</h2>
            <p><strong>Gaji:</strong> {job.gaji}</p>
            <p><strong>Kategori:</strong> {job.kategori}</p>
            <p><strong>Deskripsi:</strong> {job.desc}</p>
        </div>
    );
};

export default JobDetail;
